  ('retired-7c9828ae-moex-00181', 'retired-7c9828ae', 'retired-7c9828ae-moex-112-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'essay', '內政部就某警察特考三等考試錄取人員請求安排至警察大學接受訓練
